column7:
DROP TABLE ClassMembers; 
select * INTO ClassMembers  FROM
openquery([10.0.0.5],'SELECT * FROM [VersaillesClassAction].[dbo].[ClassMembers] WHERE OptInReceived IS NOT NULL');

column8:
DROP TABLE OCPEmployees; 
select *, (ID + 1000000) AS ClaimNo, CAST(0 AS bit) AS [Delete]
INTO OCPEmployees FROM ClassMembers;

DROP TABLE OCPEmployees; 
select *, (ID + 10000000) AS ClaimNo, CAST(0 AS bit) AS [Delete]
INTO OCPEmployees FROM ClassMembers;

column27:
UPDATE CleanClaims
SET IsValidLostTime = 1
WHERE ClaimFiledOnline = 1   AND Invalid = 0 AND IsValidLostTime = 0 and IsLostTimeReimbursement = 1;

column26:
BEGIN TRY
    BEGIN TRANSACTION;

    UPDATE CleanClaims
    SET Passcode = MailingList.Passcode
    FROM CleanClaims
    INNER JOIN MailingList ON CleanClaims.MailingListID = MailingList.ID;

    COMMIT TRANSACTION;
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0
        ROLLBACK TRANSACTION;
END CATCH;

BEGIN TRANSACTION;

UPDATE CleanClaims
SET 
    SubClass1_Weight = MailingList.SubClass1_Weight, 
    SubClass1_Amt = MailingList.SubClass1_Amt
FROM MailingList
INNER JOIN CleanClaims ON MailingList.ID = CleanClaims.MailingListID;

COMMIT TRANSACTION;
